import{_ as o,c as a,o as t,a3 as i}from"./chunks/framework.IjbGqw7S.js";const p=JSON.parse('{"title":"Privacy Policy","description":"A full declaration of the privacy for MMRL users on the website and the app","frontmatter":{"title":"Privacy Policy","description":"A full declaration of the privacy for MMRL users on the website and the app"},"headers":[],"relativePath":"legal/privacy.md","filePath":"en/legal/privacy.md"}'),r={name:"legal/privacy.md"};function s(n,e,l,c,h,d){return t(),a("div",{"data-pagefind-body":!0},e[0]||(e[0]=[i('<h1 id="privacy-policy" tabindex="-1">Privacy Policy <a class="header-anchor" href="#privacy-policy" aria-label="Permalink to &quot;Privacy Policy&quot;">​</a></h1><p>This privacy notice for MMRL (&quot;we,&quot; &quot;us,&quot; or &quot;our&quot;), describes how and why we might collect, store, use, and/or share (&quot;process&quot;) your information when you use our services (&quot;Services&quot;), such as when you:</p><ul><li>Visit our website at <a href="https://mmrl.dev" target="_blank" rel="noreferrer">https://mmrl.dev</a> or any website of ours that links to this privacy notice</li><li>Download and use our mobile application (any app), or any other application of ours that links to this privacy notice</li><li>Engage with us in other related ways, including any sales, marketing, or events</li></ul><h2 id="information-collection-and-use" tabindex="-1">Information Collection and Use <a class="header-anchor" href="#information-collection-and-use" aria-label="Permalink to &quot;Information Collection and Use&quot;">​</a></h2><p>For a better experience, while using our Service, I may require you to provide us with certain personally identifiable information. The information that I request will be retained on your device and is not collected by me in any way.</p><p>The app does use third-party services that may collect information used to identify you.</p><p>Link to the privacy policy of third-party service providers used by our app&#39;s</p><ul><li><a href="https://www.google.com/policies/privacy" target="_blank" rel="noreferrer">Google Play Services</a> <sup>(Google Play releases only)</sup></li><li><a href="https://policies.google.com/technologies/ads" target="_blank" rel="noreferrer">Google Advertising</a> <sup>(Website only)</sup></li></ul><h2 id="log-data" tabindex="-1">Log Data <a class="header-anchor" href="#log-data" aria-label="Permalink to &quot;Log Data&quot;">​</a></h2><p>I want to inform you that whenever you use my Service, in a case of an error in the app I collect data and information (through third-party products) on your phone called Log Data. This Log Data may include information such as your device Internet Protocol (&quot;IP&quot;) address, device name, operating system version, the configuration of the app when utilizing my Service, the time and date of your use of the Service, and other statistics. Collected data will be deleted after 90 days of logging. Your data will not be used to produce weapons-grade plutonium.</p><h2 id="cookies" tabindex="-1">Cookies <a class="header-anchor" href="#cookies" aria-label="Permalink to &quot;Cookies&quot;">​</a></h2><p>Cookies are files with a small amount of data that are commonly used as anonymous unique identifiers. These are sent to your browser from the websites that you visit and are stored on your device&#39;s internal memory.</p><p>This Service does not use these &quot;cookies&quot; explicitly. However, the app may use third-party code and libraries that use &quot;cookies&quot; to collect information and improve their services. You have the option to either accept or refuse these cookies and know when a cookie is being sent to your device. If you choose to refuse our cookies, you may not be able to use some portions of this Service.</p><h2 id="service-providers" tabindex="-1">Service Providers <a class="header-anchor" href="#service-providers" aria-label="Permalink to &quot;Service Providers&quot;">​</a></h2><p>I may employ third-party companies and individuals due to the following reasons:</p><ul><li>To facilitate our Service;</li><li>To provide the Service on our behalf;</li><li>To perform Service-related services; or</li><li>To assist us in analyzing how our Service is used.</li></ul><p>I want to inform users of this Service that these third parties have access to their Personal Information. The reason is to perform the tasks assigned to them on our behalf. However, they are obligated not to disclose or use the information for any other purpose.</p><h2 id="security" tabindex="-1">Security <a class="header-anchor" href="#security" aria-label="Permalink to &quot;Security&quot;">​</a></h2><p>I value your trust in providing us your Personal Information, thus we are striving to use commercially acceptable means of protecting it. But remember that no method of transmission over the internet, or method of electronic storage is 100% secure and reliable, and I cannot guarantee its absolute security.</p><h2 id="links-to-other-sites" tabindex="-1">Links to Other Sites <a class="header-anchor" href="#links-to-other-sites" aria-label="Permalink to &quot;Links to Other Sites&quot;">​</a></h2><p>This Service may contain links to other sites. If you click on a third-party link, you will be directed to that site. Note that these external sites are not operated by me. Therefore, I strongly advise you to review the Privacy Policy of these websites. I have no control over and assume no responsibility for the content, privacy policies, or practices of any third-party sites or services.</p><h2 id="children-s-privacy" tabindex="-1">Children’s Privacy <a class="header-anchor" href="#children-s-privacy" aria-label="Permalink to &quot;Children’s Privacy&quot;">​</a></h2><p>These Services do not address anyone under the age of 13. I do not knowingly collect personally identifiable information from children under 13 years of age. In the case I discover that a child under 13 has provided me with personal information, I immediately delete this from our servers. If you are a parent or guardian and you are aware that your child has provided us with personal information, please contact me so that I will be able to do the necessary actions.</p><h2 id="changes-to-this-privacy-policy" tabindex="-1">Changes to This Privacy Policy <a class="header-anchor" href="#changes-to-this-privacy-policy" aria-label="Permalink to &quot;Changes to This Privacy Policy&quot;">​</a></h2><p>I may update our Privacy Policy from time to time. Thus, you are advised to review this page periodically for any changes. I will notify you of any changes by posting the new Privacy Policy on this page.</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>This policy is effective as of 01.03.2025</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h2 id="contact-us" tabindex="-1">Contact Us <a class="header-anchor" href="#contact-us" aria-label="Permalink to &quot;Contact Us&quot;">​</a></h2><p>If you have any questions or suggestions about my Privacy Policy, do not hesitate to contact me at <a href="mailto:jimmy@dergoogler.com" target="_blank" rel="noreferrer">jimmy@dergoogler.com</a>.</p>',28)]))}const y=o(r,[["render",s]]);export{p as __pageData,y as default};
